import request from '@/utils/request';
export default {
  getList: function getList(params) {
    return request({
      url: '/workflow/request/list',
      method: 'get',
      params: params
    });
  },
  getTasks: function getTasks(params) {
    return request({
      url: '/workflow/request/tasks',
      method: 'get',
      params: params
    });
  },
  completeTask: function completeTask(params) {
    return request({
      url: '/workflow/request/completeTask',
      method: 'post',
      params: params
    });
  },
  add: function add(params) {
    return request({
      url: '/workflow/request',
      method: 'post',
      params: params
    });
  },
  update: function update(params) {
    return request({
      url: '/workflow/request',
      method: 'PUT',
      params: params
    });
  },
  remove: function remove(id) {
    return request({
      url: '/workflow/request',
      method: 'delete',
      params: {
        id: id
      }
    });
  }
};
